create table dirkspzm32.isi_db_aktivitaet (
    id               number(14, 0) not null enable,
    time             timestamp(6) not null enable,
    aktion           varchar2(1 char),
    tab_name         varchar2(80 char),
    tab_pk_feldname  varchar2(100 char),
    tab_pk_feldwert  varchar2(2048 char),
    quell_row_id     rowid,
    seq_name         varchar2(80 char),
    tab_pk_feldw_new varchar2(2048 char),
    tab_pk_feldw_old varchar2(2048 char)
);

alter table dirkspzm32.isi_db_aktivitaet
    add constraint pk_isi_db_aktivitaet primary key ( id )
        using index enable;


